targets.expr:
sum by(uri, method) (
  rate(http_server_requests_seconds_count{
    method!~"GET|OPTIONS|HEAD",
    namespace=~"$namespace",
    uri!~"^/actuator/health(/.*)?$|^/actuator/prometheus$|.*/mcp.*",
    uri!~".*/search.*|.*/statistics.*",
  }[$__rate_interval]) != 0
)

